 1→<script webc:type="render" webc:is="template">
 2→  module.exports = function () {
 3→    const seededRandom = (seed) => {
 4→      let s = seed | 0;
 5→      return () => {
 6→        s = (s * 1103515245 + 12345) & 0x7fffffff;
 7→        return s / 0x7fffffff;
 8→      };
 9→    };
10→
11→    const pointsToPath = (coords) => {
12→      const n = coords.length;
13→      if (n < 2) return "";
14→      const f = (v) => v.toFixed(2);
15→      const tension = 0.3;
16→
17→      let d = `M ${f(coords[0][0])} ${f(coords[0][1])}`;
18→      for (let i = 0; i < n - 1; i++) {
19→        const p0 = coords[i === 0 ? 0 : i - 1];
20→        const p1 = coords[i];
21→        const p2 = coords[i + 1];
22→        const p3 = coords[i + 2 < n ? i + 2 : n - 1];
23→
24→        const cp1x = p1[0] + (p2[0] - p0[0]) * tension;
25→        const cp1y = p1[1] + (p2[1] - p0[1]) * tension;
26→        const cp2x = p2[0] - (p3[0] - p1[0]) * tension;
27→        const cp2y = p2[1] - (p3[1] - p1[1]) * tension;
28→
29→        d += ` C ${f(cp1x)} ${f(cp1y)} ${f(cp2x)} ${f(cp2y)} ${f(p2[0])} ${f(p2[1])}`;
30→      }
31→      return d;
32→    };
33→
34→    const year = parseInt(this.year) || 2024;
35→    const count = parseInt(this.count) || 8;
36→    const width = parseInt(this.width) || 250;
37→    const height = parseInt(this.height) || 25;
38→
39→    const rng = seededRandom(year * 100 + count);
40→    const numPoints = 15;
41→    const numLines = 3 + Math.floor(count * 0.4);
42→
43→    const pad = 2;
44→    const numFrames = 3;
45→
46→    const paths = [];
47→    for (let i = 0; i < numLines; i++) {
48→      const startY = rng() * height;
49→      const endY = rng() * height * 0.1;
50→
51→      // Pre-compute the fixed x and baseY for each point
52→      const base = [];
53→      for (let j = 0; j <= numPoints; j++) {
54→        const t = j / numPoints;
55→        const x = pad + t * (width - pad * 2);
56→        const baseY = startY + (endY - startY) * t;
57→        const spread = 1 - t * 0.8;
58→        base.push({ x, baseY, spread });
59→      }
60→
61→      // Generate wobble variations
62→      const frames = [];
63→      for (let f = 0; f < numFrames; f++) {
64→        const coords = base.map(({ x, baseY, spread }, j) => {
65→          if (j === 0 || j === numPoints) return [x, baseY];
66→          const wobble = (rng() - 0.5) * height * 0.45 * spread;
67→          const y = Math.max(pad, Math.min(height - pad, baseY + wobble));
68→          return [x, y];
69→        });
70→        frames.push(pointsToPath(coords));
71→      }
72→
73→      const strokeWidth = (0.25 + rng() * 0.25).toFixed(2);
74→      const dur = (10 + rng() * 10).toFixed(1);
75→      const values = [...frames, frames[0]].join(";");
76→      paths.push(
77→        `<path d="${frames[0]}" fill="none" stroke="currentColor" stroke-width="${strokeWidth}" stroke-linecap="round"><animate attributeName="d" values="${values}" dur="${dur}s" repeatCount="indefinite" /></path>`,
78→      );
79→    }
80→
81→    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" aria-hidden="true">${paths.join("")}</svg>`;
82→  };
83→</script>
