 1→<script webc:type="render" webc:is="template">
 2→  module.exports = function () {
 3→    const seededRandom = (seed) => {
 4→      let s = seed | 0;
 5→      return () => {
 6→        s = (s * 1103515245 + 12345) & 0x7fffffff;
 7→        return s / 0x7fffffff;
 8→      };
 9→    };
10→
11→    const pointsToPath = (coords) => {
12→      const n = coords.length;
13→      if (n < 2) return "";
14→      const f = (v) => v.toFixed(2);
15→
16→      let d = `M ${f(coords[0][0])} ${f(coords[0][1])}`;
17→      for (let i = 1; i < n; i++) {
18→        d += ` L ${f(coords[i][0])} ${f(coords[i][1])}`;
19→      }
20→      return d;
21→    };
22→
23→    const year = parseInt(this.year) || 2024;
24→    const count = parseInt(this.count) || 8;
25→    const width = parseInt(this.width) || 250;
26→    const height = parseInt(this.height) || 25;
27→
28→    const rng = seededRandom(year * 100 + count);
29→    const numPoints = 15;
30→    const numLines = 3 + Math.floor(count * 0.4);
31→
32→    const pad = 2;
33→    const numFrames = 8;
34→
35→    const paths = [];
36→    for (let i = 0; i < numLines; i++) {
37→      const startY = rng() * height;
38→      const endY = rng() * height * 0.1;
39→
40→      // Pre-compute the fixed x and baseY for each point
41→      const base = [];
42→      for (let j = 0; j <= numPoints; j++) {
43→        const t = j / numPoints;
44→        const x = pad + t * (width - pad * 2);
45→        const baseY = startY + (endY - startY) * t;
46→        const spread = 1 - t * 0.8;
47→        base.push({ x, baseY, spread });
48→      }
49→
50→      // Generate wobble variations
51→      const frames = [];
52→      for (let f = 0; f < numFrames; f++) {
53→        const coords = base.map(({ x, baseY, spread }, j) => {
54→          if (j === 0 || j === numPoints) return [x, baseY];
55→          const wobble = (rng() - 0.5) * height * 0.45 * spread;
56→          const y = Math.max(pad, Math.min(height - pad, baseY + wobble));
57→          return [x, y];
58→        });
59→        frames.push(pointsToPath(coords));
60→      }
61→
62→      const strokeWidth = (0.25 + rng() * 0.5).toFixed(2);
63→      const dur = (2 + rng() * 3).toFixed(1);
64→      const values = [...frames, frames[0]].join(";");
65→      paths.push(
66→        `<path d="${frames[0]}" fill="none" stroke="currentColor" stroke-width="${strokeWidth}" stroke-linecap="butt"><animate attributeName="d" values="${values}" dur="${dur}s" calcMode="discrete" repeatCount="indefinite" /></path>`,
67→      );
68→    }
69→
70→    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" aria-hidden="true">${paths.join("")}</svg>`;
71→  };
72→</script>
