.listed-item {
  padding-bottom: 1.75em;
}

.listed-item time,
.book-current {
  display: block;
  font-family: var(--font-accent);
  font-size: 0.9rem;
  margin-bottom: 0.4em;
  text-transform: uppercase;
}

.listed-item__link {
  border-bottom: 1px solid color-mix(in srgb, currentColor 50%, transparent);
  color: var(--color-accent-primary);
  font-size: 1.4em;
  line-height: 1.35;
  max-width: 100%;
  text-decoration: none;
  word-wrap: break-word;
}

.listed-item__link:hover,
.listed-item__link:focus-visible {
  color: var(--color-text);
}

.listed-item p {
  max-width: 55ch;
}

.listed-item p {
  font-size: 1.1em;
  line-height: 1.5;
  margin-top: 0.2em;
}

.listed-items__heading {
  font-family: var(--font-proto-regular);
  font-size: 1.25rem;
}

@media (min-width: 620px) {
  .listed-items {
    --num-cols: 3;
  }

  .listed-items__heading {
    --col-start: 1;
  }

  .listed-item {
    --col-start: 2;
    --col-end: span 2;
  }
}

@media (min-width: 1040px) {
  .listed-items {
    --num-cols: 5;
  }

  .listed-item {
    --col-end: span 3;
  }
}

@media (min-width: 1700px) {
  .listed-items {
    --num-cols: 9;
  }

  .listed-items__heading {
    --col-start: 2;
  }

  .listed-item {
    --col-start: 3;
    --col-end: span 5;
  }
}

@media (min-width: 1980px) {
  .listed-items__heading {
    top: 2rem;
  }
}

@media (min-width: 2200px) {
  .listed-items {
    font-size: 1.2em;
  }
}

