.bio__intro p:first-child::first-line {
  font-size: 75%;
  font-family: var(--font-proto-bold);
  text-transform: uppercase;
}

.bio__design,
.bio__eng {
  font-size: 82%;
}

.highlight--about {
  background-color: #c91c3331;
}

.about-section__intro {
  font-size: 1.3em;
  line-height: 1.6;
  margin-top: calc(var(--g-row) * 8);
}

.site__versions {
  --col-start: 1;
  --col-end: -1;
}

.version {
  margin-bottom: 4rem;
}

.version__link {
  display: block;
  text-decoration: none;
}

.version__link:focus {
  outline: none;
}

.version__link:hover,
.version__link:focus {
  --border-color: var(--color-accent-primary);
}

.version__title {
  font-size: 1.5rem;
  margin-bottom: 0.5rem;
}

.version__title b {
  color: var(--color-text);
  display: block;
  font-family: var(--font-proto-regular);
  font-size: 0.9rem;
  font-weight: normal;
  margin-bottom: 0.4em;
  text-transform: uppercase;
}

.version__img {
  display: block;
  position: relative;
}

.version__img::after {
  border-radius: 6px;
  box-shadow: inset 0 0 0 4px var(--border-color);
  content: "";
  display: block;
  height: 100%;
  position: absolute;
  top: 0;
  transition: 0.1s ease;
  width: 100%;
  z-index: 2;
}

.version__img img {
  border-radius: 6px;
  display: block;
  height: auto;
  width: 100%;
}

.about__photo {
  border-radius: 2px;
  overflow: hidden;
}

.about__polaroids picture:nth-child(1) img {
  rotate: 1deg;
  translate: 0 -0.4rem;
}

.about__polaroids picture:nth-child(2) img {
  rotate: -1.1deg;
  translate: 0.2rem 0.4rem;
}

.about__polaroids picture:nth-child(3) img {
  rotate: 1deg;
  translate: -0.2rem 0.8rem;
}

@media (min-width: 38.75em) {
  .hero--about::before {
    --height: 65%;
  }

  .about__hero-contents {
    --trans-y: -5%;
    margin-bottom: var(--trans-y);
    transform: translateY(var(--trans-y));
  }

  .about__title {
    --pos-top: 28%;
    --size-lower: 9vw;
    text-align: left;
    width: 63%;
  }

  .about__portrait img {
    --trans-x: -38%;
    margin: 0;
  }

  .about-section__intro {
    --col-end: span 2;
  }

  .site__versions {
    --gap: calc(25 / 16 * 1rem);
    display: flex;
    flex-wrap: wrap;
    gap: var(--gap);
  }

  .version {
    width: calc(var(--width-target, 50%) - calc(var(--gap) / 2));
  }
}

@media (min-width: 46.875em) {
  .about__bio {
    font-size: 1.8em;
  }
}

@media (min-width: 65em) {
  .bio__intro,
  .bio__outro {
    --col-start: 2;
    --col-end: span 4;
    padding-right: 3em;
  }

  .bio__design,
  .about-section__intro,
  .site__versions {
    --col-start: 2;
  }

  .bio__design,
  .bio__eng {
    --col-end: span 2;
  }

  .about-section__intro {
    --col-end: span 3;
  }
}

@media (min-width: 71.25em) {
  .about__title {
    width: 55%;
  }
}

@media (min-width: 77.5em) {
  .about__bio {
    font-size: 2em;
  }

  .bio__intro,
  .bio__outro {
    --col-end: span 5;
  }

  .about-section__intro {
    --col-end: span 4;
  }
}

@media (min-width: 90em) {
  .hero--about::before {
    --height: 60%;
  }

  .about__hero-contents {
    --trans-y: -10%;
    margin-bottom: -4rem;
  }

  .about__portrait img {
    --trans-x: -15%;
  }

  .about__title {
    --pos-top: 33%;
    width: 45%;
  }
}

@media (min-width: 106.25em) {
  .about__hero-contents {
    max-width: 1835px;
  }

  .about__portrait img {
    --trans-x: 0;
  }

  .bio__intro,
  .bio__outro {
    --col-end: span 6;
  }

  .bio__design,
  .bio__eng {
    --col-end: span 3;
  }

  .version {
    --width-target: 33%;
  }
}

@media (min-width: 137.5em) {
  .about__bio {
    font-size: 2.2em;
  }

  .bio__intro,
  .bio__outro,
  .bio__design,
  .about-section__intro,
  .site__versions {
    --col-start: 3;
  }

  .bio__design,
  .bio__eng {
    --col-end: span 4;
    padding-right: 2.5em;
  }
}

@layer baseline, tokens, components, pages;


@import url("./modules/pages/about.css") layer(pages);
@import url("./modules/pages/article.css") layer(pages);
@import url("./modules/pages/home.css") layer(pages);
@import url("./modules/pages/work/project-base.css") layer(pages);
@import url("./modules/pages/work/limbo.css") layer(pages);
@import url("./modules/pages/work/groundwork.css") layer(pages);
@import url("./modules/pages/work/colorme.css") layer(pages);
@import url("./modules/pages/work/osx-apps-with-js.css") layer(pages);
@import url("./modules/pages/work/streetcred.css") layer(pages);
@import url("./modules/pages/purpose.css") layer(pages);
@import url("./modules/pages/resume.css") layer(pages);
@import url("./modules/pages/art.css") layer(pages);

/* 
FIXME: There's some dumbass bug with view transitions that is causing about
a 1 second freeze of the entire screen on pages that don't have customized
transitions when coming to them from a page that does. (or something like that)
@view-transition {
  navigation: auto;
} 
*/

@layer baseline {
  html,
  div,
  span,
  object,
  iframe,
  p,
  blockquote,
  pre,
  a,
  abbr,
  acronym,
  address,
  cite,
  code,
  del,
  dfn,
  em,
  img,
  q,
  s,
  small,
  strike,
  strong,
  sub,
  sup,
  var,
  b,
  u,
  i,
  center,
  dl,
  dt,
  dd,
  ol,
  ul,
  li,
  fieldset,
  form,
  label,
  legend,
  table,
  caption,
  tbody,
  tfoot,
  thead,
  tr,
  th,
  td,
  article,
  aside,
  canvas,
  embed,
  figure,
  figcaption,
  footer,
  header,
  nav,
  section,
  time,
  mark,
  audio,
  video {
    margin: 0;
    padding: 0;
    border: 0;
    font: inherit;
    font-size: 100%;
    vertical-align: baseline;
  }

  article,
  aside,
  details,
  figcaption,
  figure,
  footer,
  header,
  hgroup,
  menu,
  nav,
  section {
    display: block;
  }

  ol,
  ul {
    list-style: none;
  }

  blockquote,
  q {
    quotes: none;
  }

  blockquote:before,
  blockquote:after,
  q:before,
  q:after {
    content: "";
    content: none;
  }

  i,
  em {
    font-style: normal;
  }

  * {
    box-sizing: border-box;
  }

  :root {
    --link-border: 1px solid color-mix(in srgb, currentColor 50%, transparent);
  }

  html,
  body {
    margin: 0;
    border: 0;
  }

  .visually-hidden {
    position: absolute !important;
    height: 1px;
    width: 1px;
    overflow: hidden;
    clip: rect(1px, 1px, 1px, 1px);
    white-space: nowrap;
  }

  .list--normal {
    list-style: inside;
    padding-bottom: 2rem;
    margin-top: 0;
  }

  .bordered-link {
    border-bottom: var(--link-border);
    text-decoration: none;
  }
}

@layer tokens {
  :root {
    color-scheme: light dark;

    /* Accent colors */
    --color-accent-toxic: #00eb9b;
    --color-accent-wine: #c01458;
    --color-accent-boo: #9db4ff;
    --color-accent-pank: #f2c0ea;
    --color-accent-boogers: #c2d838;
    --color-accent-mellow: #f1f68e;
    --color-accent-orange: #e9b581;

    /* Project and page colors */
    --color-streetcred-accent: #8e42f5;
    --color-streetcred-accent-dark: #400099;
    --color-streetcred-accent-light: #dcc2ff;

    --color-limbo-accent: #dd3535;
    --color-limbo-accent-dark: #800000;
    --color-limbo-accent-light: #f9c5c5;

    --color-colorme-accent: #b42e8a;
    --color-colorme-accent-dark: #8c0060;

    --color-groundwork-accent: #3b6fd8;
    --color-groundwork-accent-dark: #1a4293;
    --color-groundwork-accent-light: #a4bff4;

    --color-jxa-accent: #151414;
    --color-jxa-accent-light: #5b5757;

    --color-archive-accent: #66fa32;
    --color-archive-accent-dark: #2d8f22;

    --color-about-accent: #c91c33;
    --color-about-accent-dark: #871222;
    --color-about-accent-light: #f58998;

    --color-blog-accent: #ff902b;
    --color-blog-accent-dark: #b35600;

    /* Common colors */
    --color-charcoal: #292929;
    --color-mud: #3f3d31;
    --color-offwhite: #fcfcfc;
    --color-white: #fff;
    --color-eggshell: #f6f5e4;

    --color-accent-primary: light-dark(
      var(--color-accent-wine),
      var(--color-accent-toxic)
    );
    --color-accent-secondary: light-dark(
      var(--color-accent-boogers),
      var(--color-accent-boo)
    );
    --color-bg: light-dark(var(--color-offwhite), var(--color-charcoal));
    --color-bg-offset: light-dark(white, #1f1f1f);
    --color-text: light-dark(var(--color-mud), var(--color-offwhite));
  }

  [data-page="home"] {
    --color-accent-primary: color(display-p3 1 0 0);
  }

  [data-page="blog"] {
    --color-accent-primary: color(display-p3 1 0.4 0);
  }

  [data-page="about"] {
    --color-accent-primary: color(display-p3 0 0 0);
  }

  [data-page="books"] {
    --color-accent-primary: color(display-p3 0 0 1);
  }

  [data-page="work-streetcred"] {
    --color-accent-primary: var(--color-streetcred-accent);
  }

  [data-page="work-limbo"] {
    --color-accent-primary: var(--color-limbo-accent);
  }

  [data-page="work-groundwork"] {
    --color-accent-primary: var(--color-groundwork-accent);
  }

  [data-page="work-jxa"] {
    --color-accent-primary: light-dark(
      var(--color-jxa-accent),
      var(--color-jxa-accent-light)
    );
  }

  [data-page="work-colorme"] {
    --color-accent-primary: var(--color-colorme-accent);
  }

  html,
  body {
    background: var(--color-bg);
    color: var(--color-text);
  }

  :root {
    --g-row: calc(10 / 16 * 1rem);
    --g-col: calc(140 / 16 * 1rem);
    --g-gutter: 1rem;
    --g-padding-h: 1rem;

    --g-max-1: calc(var(--g-col) * 1);
    --g-max-2: calc(var(--g-col) * 2 + var(--g-gutter) * 1);
    --g-max-3: calc(var(--g-col) * 3 + var(--g-gutter) * 2);
    --g-max-4: calc(var(--g-col) * 4 + var(--g-gutter) * 3);
    --g-max-5: calc(var(--g-col) * 5 + var(--g-gutter) * 4);
    --g-max-6: calc(var(--g-col) * 6 + var(--g-gutter) * 5);
    --g-max-7: calc(var(--g-col) * 7 + var(--g-gutter) * 6);
    --g-max-8: calc(var(--g-col) * 8 + var(--g-gutter) * 7);
    --g-max-9: calc(var(--g-col) * 9 + var(--g-gutter) * 8);
    --g-max-10: calc(var(--g-col) * 10 + var(--g-gutter) * 9);
  }

  .g-main {
    display: grid;
    gap: var(--g-gutter);
    grid-template-columns: repeat(var(--num-cols, 1), 1fr);
  }

  .g-main__item {
    grid-column: var(--col-start, auto) / var(--col-end, auto);
    grid-row: var(--row-start, auto) / var(--row-end, auto);
  }

  .g-padded {
    padding-left: var(--g-padding-h);
    padding-right: var(--g-padding-h);
  }

  @media (min-width: 620px) {
    .g-main {
      --num-cols: 2;
    }

    .g-standard-a {
      --num-cols: 3;
    }

    .g-standard-a__item {
      --col-start: 2;
      --col-end: span 2;
    }
  }

  @media (min-width: 730px) {
    :root {
      --g-padding-h: 2rem;
      --g-gutter: calc(21 / 16 * 1rem);
    }
  }

  @media (min-width: 1040px) {
    .g-main,
    .g-standard-a {
      --num-cols: 5;
    }

    .g-standard-a__item {
      --col-end: span 3;
    }
  }

  @media (min-width: 1240px) {
    .g-main {
      --num-cols: 6;
    }

    .g-standard-a {
      --num-cols: 5;
    }
  }

  @media (min-width: 1660px) {
    .g-main,
    .g-standard-a {
      --num-cols: 10;
    }

    .g-standard-a__item {
      --col-start: 3;
      --col-end: span 5;
    }
  }

  @media (min-width: 2200px) {
    .g-main:not(.g-standard-a) {
      --num-cols: 11;
    }
  }

  @font-face {
    font-display: swap;
    font-family: "protogrotesk-bold";
    src: url("/fonts/protogroteskweb-bold.woff2");
  }

  @font-face {
    font-display: swap;
    font-family: "protogrotesk-extralight";
    src: url("/fonts/protogroteskweb-extralight.woff2");
    font-weight: 200;
  }

  @font-face {
    font-display: swap;
    font-family: "protogrotesk-light";
    src: url("/fonts/protogroteskweb-light.woff2");
  }

  @font-face {
    font-display: swap;
    font-family: "protogrotesk-regular";
    src: url("/fonts/protogroteskweb-regular.woff2");
  }

  @font-face {
    font-display: swap;
    font-family: "Dragonsteel Rough";
    font-weight: 400;
    src: url("/fonts/Dragonsteel-Rough.woff2") format("woff2");
  }

  html,
  body {
    --font-proto-extralight: "protogrotesk-extralight", helvetica, sans-serif;
    --font-proto-light: "protogrotesk-light", helvetica, sans-serif;
    --font-proto-regular: "protogrotesk-regular", helvetica, sans-serif;
    --font-proto-bold: "protogrotesk-bold", helvetica, sans-serif;
    /* FIXME: Need to buy/use real covik */
    --font-accent: "Covik Sans Mono Demo", Consolas, monospace;
    --font-mono: Consolas, Monaco, "Andale Mono", "Ubuntu Mono", monospace;
    --font-dragonsteel: "Dragonsteel Rough", helvetica, sans-serif;

    --font-size-12: calc(12 / 16 * 1rem);
    --font-size-14: calc(14 / 16 * 1rem);
    --font-size-16: 1rem;
    --font-size-18: calc(18 / 16 * 1rem);
    --font-size-20: calc(20 / 16 * 1rem);
    --font-size-24: calc(24 / 16 * 1rem);
    --font-size-28: calc(28 / 16 * 1rem);
    --font-size-30: calc(30 / 16 * 1rem);
    --font-size-34: calc(34 / 16 * 1rem);
    --font-size-36: calc(36 / 16 * 1rem);
    --font-size-44: calc(44 / 16 * 1rem);

    font-family: var(--font-proto-light);
    font-size: 100%;
    line-height: 1;
    vertical-align: baseline;
  }

  b,
  strong,
  .font--regular {
    font-family: var(--font-proto-regular);
    font-weight: normal;
  }

  a {
    color: var(--color-accent-primary);
  }

  a:focus {
    outline: 3px solid currentColor;
  }

  .heading--special {
    font-family: var(--font-proto-regular);
    font-size: 1.2rem;
    font-weight: 400;
    letter-spacing: 0.05em;
    margin: 0;
    text-transform: uppercase;
  }
}

@layer components {
  .hero--before-standard::before,
  .hero--after-standard::after {
    content: "";
    display: block;
    position: absolute;
  }

  .hero--before-standard::before,
  .hero--after-standard::after {
    --gutter: 1rem;
    --offset-v: calc(var(--gutter) * 3);
    left: var(--gutter);
    width: calc(100% - var(--gutter) * 2);
  }

  .hero--before-standard::before {
    height: calc(100% - var(--offset-v));
  }

  .hero--offset {
    --offset: -2.25rem;
    margin-bottom: var(--offset);
    transform: translateY(var(--offset));
  }

  .hero__contents {
    position: relative;
    z-index: 1;
  }

  @media (min-width: 38.75em) {
    .hero--before-standard::before,
    .hero--after-standard::after {
      left: calc(var(--gutter) * 2);
      width: calc(100% - var(--gutter) * 4);
    }
  }

  .listed-item {
    padding-bottom: 1.75em;
  }

  .listed-item time,
  .book-current {
    display: block;
    font-family: var(--font-accent);
    font-size: 0.9rem;
    margin-bottom: 0.4em;
    text-transform: uppercase;
  }

  .listed-item__link {
    border-bottom: 1px solid color-mix(in srgb, currentColor 50%, transparent);
    color: var(--color-accent-primary);
    font-size: 1.4em;
    line-height: 1.35;
    max-width: 100%;
    text-decoration: none;
    word-wrap: break-word;
  }

  .listed-item__link:hover,
  .listed-item__link:focus-visible {
    color: var(--color-text);
  }

  .listed-item p {
    max-width: 55ch;
  }

  .listed-item p {
    font-size: 1.1em;
    line-height: 1.5;
    margin-top: 0.2em;
  }

  .listed-items__heading {
    font-family: var(--font-proto-regular);
    font-size: 1.25rem;
  }

  @media (min-width: 620px) {
    .listed-items {
      --num-cols: 3;
    }

    .listed-items__heading {
      --col-start: 1;
    }

    .listed-item {
      --col-start: 2;
      --col-end: span 2;
    }
  }

  @media (min-width: 1040px) {
    .listed-items {
      --num-cols: 5;
    }

    .listed-item {
      --col-end: span 3;
    }
  }

  @media (min-width: 1700px) {
    .listed-items {
      --num-cols: 9;
    }

    .listed-items__heading {
      --col-start: 2;
    }

    .listed-item {
      --col-start: 3;
      --col-end: span 5;
    }
  }

  @media (min-width: 1980px) {
    .listed-items__heading {
      top: 2rem;
    }
  }

  @media (min-width: 2200px) {
    .listed-items {
      font-size: 1.2em;
    }
  }

  .page-intro,
  .resume-intro {
    padding-bottom: calc(var(--g-row) * var(--rows-btm, 8));
    padding-top: calc(var(--g-row) * var(--rows-top, 4));
  }

  .page-intro__body {
    font-size: 1.2em;
    line-height: 1.5;
    margin: 0.5rem 0 0 0;
  }

  .page-intro__body p {
    max-width: 62ch;
  }

  .page-intro__body p + p {
    padding-top: 1.4rem;
  }

  @media (min-width: 620px) {
    .page-intro {
      --num-cols: 3;
      --rows-top: 6;
      --rows-btm: 10;
    }

    .page-intro__contents {
      --col-start: 2;
      --col-end: span 2;
    }
  }

  @media (min-width: 1040px) {
    .page-intro {
      --num-cols: 5;
    }

    .page-intro__contents {
      --col-end: span 3;
    }
  }

  @media (min-width: 1700px) {
    .page-intro {
      --num-cols: 9;
    }

    .page-intro__contents {
      --col-start: 3;
      --col-end: span 5;
    }
  }
}

