file.content:
[data-page="blog"] {
  --width-text-max: 60.5rem;
  --width-content: 90%;
  --width-content-max: calc(var(--width-text-max) + 10rem);
}

.h-entry ::selection {
  background-color: var(--color-accent-primary);
  color: var(--color-bg);
}

.h-entry {
  overflow: hidden;
}

.e-header {
  margin: 2.5rem auto 5rem auto;
  max-width: var(--width-text-max);
  width: var(--width-content);
}

.p-name {
  font-family: var(--font-proto-light);
  font-size: 9vw;
  letter-spacing: -0.035em;
  line-height: 1.1;
  margin: 0;
  text-wrap: balance;
  font-weight: 300;
}

.dt-published {
  display: block;
  font-family: var(--font-accent);
  font-size: 1.1rem;
  margin-bottom: 0.25em;
  padding-left: 0.25em;
  text-transform: uppercase;
}

.p-author {
  display: none;
  visibility: hidden;
}

.e-content {
  color: var(--color-text);
  font-size: 1.6em;
  line-height: 1.6;
  margin: 0 auto;
  max-width: var(--width-content-max);
  padding-bottom: 1em;
  width: var(--width-content);
}

.e-content a {
  color: var(--text);
}

.e-content a:hover,
.e-content a:focus {
  color: var(--color-accent-primary);
}

.e-content .link--future {
  cursor: not-allowed;
  opacity: 0.4;
  text-decoration: underline;
}

.e-content h2,
.e-content h3,
.e-content h4,
.e-content h5,
.e-content h6,
.e-content p,
.e-content ul,
.e-content ol,
.e-content blockquote,
.e-content blockquote cite {
  margin: 0 auto;
  max-width: var(--width-text-max);
}

.e-content h3,
.e-content h4,
.e-content h5,
.e-content h6 {
  color: var(--color-text);
  font-family: var(--font-proto-regular);
  line-height: 1.3;
}

.e-content h2 {
  color: var(--color-text);
  font-family: var(--font-proto-bold);
  font-size: 1.4em;
  line-height: 1.3;
  margin-top: 1em;
  padding: 0.7em 0 0 0;
}

.e-content h3 {
  font-size: 1.1em;
  margin-top: 1.2em;
}

.e-content h3 code {
  font-family: var(--font-mono);
}

.e-content h4 {
  font-size: 0.9em;
}

.e-content p:not([class]) + p:not([class]),
:where(.note-special, .note-update, .offset-no-indent) + p {
  margin-top: 1em;
}

.e-content .offset-no-indent {
  margin-top: 4em;
}

.e-content code {
  font-size: 80%;
}

.e-content .thanks-for-reading svg {
  margin-left: auto;
  max-width: 15.625rem;
  transform: translateX(-1rem);
}

.e-content figure {
  margin: 0.2em 0 2em 0;
}

.e-content p + figure {
  margin-top: 1.5em;
}

.e-content .entry-intro + figure {
  margin-top: 0;
}

.e-content img,
.e-content picture,
.e-content video {
  display: block;
  margin: 0 auto;
  width: 100%;
}

.e-content figcaption {
  margin-top: 0.5em;
  padding-left: 0.5em;
}

.e-content figcaption,
.e-content .note,
.e-content .note-special,
.e-content .note-update {
  font-size: min(0.75em, 1.375rem);
}

.e-content p.note-special,
.e-content p.note-update {
  border-width: 1px;
  border-style: solid;
  border-radius: 4px;
  padding: 1em 1.2em;
}

.e-content p.note-special {
  border-color: #ffad154d;
  background-color: #ffad1526;
  margin-bottom: 1em;
}

.e-content p.note-update {
  border-color: #007cff4d;
  background-color: #007cff26;
  margin-bottom: 1em;
}

.e-content p + :where(.note-special, .note-update) {
  margin-top: 1.5em;
}

.e-content .e-reply {
  clear: both;
  font-size: 70%;
  margin-top: 5em;
}

.e-content .e-iframe-full {
  aspect-ratio: 16 / 9;
  height: auto;
  width: 100%;
}

.e-content ul,
.e-content ol {
  clear: both;
  margin-top: 1.5em;
  padding: 0 0.2em 1.4em 0.2em;
}

.e-content h2 + :where(ul, ol),
.e-content h3 + :where(ul, ol),
.e-content h4 + :where(ul, ol) {
  margin-top: 0.75em;
}

.e-content li {
  line-height: 1.5;
  padding-bottom: 0.25em;
  position: relative;
}

.e-content ul li {
  list-style: disc inside;
}

.e-content ol li {
  list-style: decimal inside;
}

.e-content blockquote {
  border-left: 0.4em solid var(--color-accent-primary);
  font-size: 0.9em;
  margin-top: 1.5em;
  margin-bottom: 2em;
  padding: 0.2em 1em 0.2em 1.6em;
}

.e-content blockquote p {
  padding-bottom: 0;
}

.e-content blockquote cite {
  display: block;
  font-size: 0.9em;
  margin-top: 1.2rem;
  padding-bottom: 0.2rem;
}

.e-content .entry-intro {
  font-size: 1.2em;
  line-height: 1.6;
  padding-bottom: 2em;
}

.entry-intro::first-line {
  font-size: 78%;
  font-family: var(--font-proto-bold);
  text-transform: uppercase;
}

.entry-intro + h2 {
  padding-top: 0;
}

.entry-intro + p:not(.no-drop-cap):first-letter,
.entry-intro + h2 + p:not(.no-drop-cap):first-letter,
.drop-capped:first-letter {
  color: var(--color-accent-primary);
  float: left;
  font-family: var(--font-proto-bold);
  font-size: 555%;
  line-height: 0.85;
  margin-left: -0.05em;
  padding-right: 0.07em;
}

.entry-update {
  font-size: 1em;
}

.realign-color-fig {
  --height: 650px;
  height: var(--height);
  height: min(var(--height), 50vw);
}

.realign-color-primary-accent {
  background-color: #00eb9b;
}

.realign-color-primary-secondary-accent {
  background: linear-gradient(90deg, #00eb9b 60%, #9db4ff 40%);
}

.realign-color-light-scheme {
  background: linear-gradient(90deg, #3f3d31 20%, #c01458 20% 60%, #c2d838 40%);
}

.no-js .realign-color-scheme-toggle-invite {
  display: none;
}

.realign-color-scheme-toggle {
  background-color: var(--color-accent-primary);
  border: 0;
  border-radius: 3px;
  cursor: pointer;
  display: inline-block;
  color: var(--color-bg);
  font-family: var(--font-proto-regular);
  font-size: inherit;
  font-size: 65%;
  padding: 0.5rem 0.6rem;
}

.color-swatch-code::before {
  background-color: var(--color);
  border-radius: 3px;
  border: 2px solid currentColor;
  content: "";
  display: inline-block;
  height: 0.7em;
  margin-right: 0.5rem;
  width: 0.7em;
}

.cp_embed_wrapper {
  margin-bottom: 1em;
}

@media (min-width: 750px) {
  .e-header {
    margin-bottom: 8rem;
    margin-top: 4rem;
  }

  .p-name {
    font-size: 4.2em;
  }

  .e-content {
    font-size: 1.875em;
  }
}

@media (min-width: 1550px) {
  [data-page="blog"] {
    --width-text-max: 66rem;
  }

  .e-content {
    font-size: 2em;
  }
}

@media (min-width: 1850px) {
  [data-page="blog"] {
    --width-text-max: 79rem;
  }

  .e-content {
    font-size: 2.4em;
  }
}

