  .resume-intro__contents,
  .resume__experience,
  .resume__aside {
    --col-start: 3;
    --col-end: span 5;
  }
}

@media (min-width: 137.5em) {
  .resume-intro__contents,
  .resume__experience,
  .resume__aside {
    --col-start: 4;
  }
}

