  html,
  body {
    --font-proto-extralight: "protogrotesk-extralight", helvetica, sans-serif;
    --font-proto-light: "protogrotesk-light", helvetica, sans-serif;
    --font-proto-regular: "protogrotesk-regular", helvetica, sans-serif;
    --font-proto-bold: "protogrotesk-bold", helvetica, sans-serif;
    /* FIXME: Need to buy/use real covik */
    --font-accent: "Covik Sans Mono Demo", Consolas, monospace;
    --font-mono: Consolas, Monaco, "Andale Mono", "Ubuntu Mono", monospace;
    --font-dragonsteel: "Dragonsteel Rough", helvetica, sans-serif;

    --font-size-12: calc(12 / 16 * 1rem);
    --font-size-14: calc(14 / 16 * 1rem);
    --font-size-16: 1rem;
    --font-size-18: calc(18 / 16 * 1rem);
    --font-size-20: calc(20 / 16 * 1rem);
    --font-size-24: calc(24 / 16 * 1rem);
    --font-size-28: calc(28 / 16 * 1rem);
    --font-size-30: calc(30 / 16 * 1rem);
    --font-size-34: calc(34 / 16 * 1rem);
    --font-size-36: calc(36 / 16 * 1rem);
    --font-size-44: calc(44 / 16 * 1rem);

    font-family: var(--font-proto-light);
    font-size: 100%;
    line-height: 1;
    vertical-align: baseline;
  }

  b,
  strong,
  .font--regular {
    font-family: var(--font-proto-regular);
    font-weight: normal;
  }

  a {
    color: var(--color-accent-primary);
  }

  a:focus {
    outline: 3px solid currentColor;
  }

  .heading--special {
    font-family: var(--font-proto-regular);
    font-size: 1.2rem;
    font-weight: 400;
    letter-spacing: 0.05em;
    margin: 0;
    text-transform: uppercase;
  }
}

@layer components {
  .hero--before-standard::before,
  .hero--after-standard::after {
    content: "";
    display: block;
    position: absolute;
  }

  .hero--before-standard::before,
  .hero--after-standard::after {
    --gutter: 1rem;
    --offset-v: calc(var(--gutter) * 3);
    left: var(--gutter);
    width: calc(100% - var(--gutter) * 2);
  }

  .hero--before-standard::before {
    height: calc(100% - var(--offset-v));
  }

  .hero--offset {
    --offset: -2.25rem;
    margin-bottom: var(--offset);
    transform: translateY(var(--offset));
  }

  .hero__contents {
    position: relative;
    z-index: 1;
  }

  @media (min-width: 38.75em) {
    .hero--before-standard::before,
    .hero--after-standard::after {
      left: calc(var(--gutter) * 2);
      width: calc(100% - var(--gutter) * 4);
    }
  }

  .listed-item {
    padding-bottom: 1.75em;
  }

  .listed-item time,
  .book-current {
    display: block;
    font-family: var(--font-accent);
    font-size: 0.9rem;
    margin-bottom: 0.4em;
    text-transform: uppercase;
  }

  .listed-item__link {
    border-bottom: 1px solid color-mix(in srgb, currentColor 50%, transparent);
    color: var(--color-accent-primary);
    font-size: 1.4em;
    line-height: 1.35;
    max-width: 100%;
    text-decoration: none;
    word-wrap: break-word;
  }

  .listed-item__link:hover,
  .listed-item__link:focus-visible {
    color: var(--color-text);
  }

  .listed-item p {
    max-width: 55ch;
  }

  .listed-item p {
    font-size: 1.1em;
    line-height: 1.5;
    margin-top: 0.2em;
  }

  .listed-items__heading {
    font-family: var(--font-proto-regular);
    font-size: 1.25rem;
  }

  @media (min-width: 620px) {
    .listed-items {
      --num-cols: 3;
    }

    .listed-items__heading {
      --col-start: 1;
    }

    .listed-item {
      --col-start: 2;
      --col-end: span 2;
    }
  }

  @media (min-width: 1040px) {
    .listed-items {
      --num-cols: 5;
    }

    .listed-item {
      --col-end: span 3;
    }
  }

  @media (min-width: 1700px) {
    .listed-items {
      --num-cols: 9;
    }

    .listed-items__heading {
      --col-start: 2;
    }

    .listed-item {
      --col-start: 3;
      --col-end: span 5;
    }
  }

  @media (min-width: 1980px) {
    .listed-items__heading {
      top: 2rem;
    }
  }

  @media (min-width: 2200px) {
    .listed-items {
      font-size: 1.2em;
    }
  }

  .page-intro,
  .resume-intro {
    padding-bottom: calc(var(--g-row) * var(--rows-btm, 8));
    padding-top: calc(var(--g-row) * var(--rows-top, 4));
  }

  .page-intro__body {
    font-size: 1.2em;
    line-height: 1.5;
    margin: 0.5rem 0 0 0;
  }

  .page-intro__body p {
    max-width: 62ch;
  }

  .page-intro__body p + p {
    padding-top: 1.4rem;
  }

  @media (min-width: 620px) {
    .page-intro {
      --num-cols: 3;
      --rows-top: 6;
      --rows-btm: 10;
    }

    .page-intro__contents {
      --col-start: 2;
      --col-end: span 2;
    }
  }

  @media (min-width: 1040px) {
    .page-intro {
      --num-cols: 5;
    }

    .page-intro__contents {
      --col-end: span 3;
    }
  }

  @media (min-width: 1700px) {
    .page-intro {
      --num-cols: 9;
    }

    .page-intro__contents {
      --col-start: 3;
      --col-end: span 5;
    }
  }
}

