.project__specs li {
  width: 100%;
}

.spec__title {
  font-size: var(--font-size-16);
  margin-bottom: 0;
}

.spec__desc {
  font-size: var(--font-size-18);
  line-height: 1.33;
  margin-top: calc(8 / 16 * 1rem);
  max-width: 20ch;
}

.project__body--initial {
  padding-top: calc(var(--g-row) * 6);
}

.project__body p,
.project__body ul,
.project__body ol {
  font-size: var(--font-size-20);
}

.project__body p,
.project__list-item-p,
.project__figure figcaption {
  max-width: 70ch;
}

.project__body li {
  list-style: disc inside;
  margin-top: 0.75rem;
}

.project__body p,
.project__list-item-p,
.project__figure figcaption {
  line-height: 1.6;
}

.project__body p + p {
  margin-top: 1.4rem;
}

.project__body h3 {
  font-family: var(--font-proto-regular);
  font-size: var(--font-size-30);
  font-weight: normal;
  line-height: 1.3;
  margin-bottom: 0;
  margin-top: 1.5em;
}

.project__body h4 {
